#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;

class KernelCa6k00322Custom {
public:
    __aicore__ inline KernelCa6k00322Custom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                int32_t groups, uint32_t channels,
                                uint32_t height, uint32_t width)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        groups_ = groups;
        channels_ = channels;
        height_ = height;
        width_ = width;
        // Stride for spatial and channel dimensions
        spatialStride_ = height_ * width_;
        channelStride_ = spatialStride_;
        // Total elements per N
        perBatch_ = channels_ * spatialStride_;

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0) return;

        const uint32_t blockNum = static_cast<uint32_t>(AscendC::GetBlockNum());
        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        // Tile-granularity grid-stride to improve load balance and occupancy.
        const uint32_t strideElems = blockNum * tileLen_;
        uint32_t base = blockIdx * tileLen_;
        if (base >= totalLen_) return;

        while (true) {
            uint32_t curLen = totalLen_ - base;
            if (curLen > tileLen_) curLen = tileLen_;
            if (curLen == 0) break;

            Compute(base, curLen);
            CopyOut(base, curLen);

            base += strideElems;
        }
    }

private:
    __aicore__ inline void Compute(uint32_t base, uint32_t len)
    {
        AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();

        for (uint32_t i = 0; i < len; i++) {
            uint32_t outIdx = base + i;
            // Decompose output linear index into (n, c, h, w)
            uint32_t n = outIdx / perBatch_;
            uint32_t rem = outIdx % perBatch_;
            uint32_t c = rem / channelStride_;
            uint32_t rem2 = rem % channelStride_;
            uint32_t h = rem2 / width_;
            uint32_t w = rem2 % width_;

            // Compute source channel
            uint32_t channelsPerGroup = channels_ / groups_;
            uint32_t cSrc = (c % groups_) * channelsPerGroup + (c / groups_);
            uint32_t srcIdx = n * perBatch_ + cSrc * channelStride_ + h * width_ + w;

            // Read from global memory and store in local output tensor
            float val = xGm_[srcIdx];
            yLocal.SetValue(i, val);
        }

        outQueueY_.EnQue<float>(yLocal);
    }

    __aicore__ inline void CopyOut(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    int32_t groups_ {1};
    uint32_t channels_ {0};
    uint32_t height_ {0};
    uint32_t width_ {0};
    uint32_t spatialStride_ {0};
    uint32_t perBatch_ {0};
};

extern "C" __global__ __aicore__ void ca6k_00322_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelCa6k00322Custom op;
    op.Init(x, y,
            tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.groups, tiling_data.channels,
            tiling_data.height, tiling_data.width);
    op.Process();
}
